    /**
     * An enum for determining the page role inside the {@link Gtk.Assistant}. It's
     * used to handle buttons sensitivity and visibility.
     * 
     * Note that an assistant needs to end its page flow with a page of type
     * {@link Gtk.AssistantPageType.CONFIRM}, {@link Gtk.AssistantPageType.SUMMARY} or
     * {@link Gtk.AssistantPageType.PROGRESS} to be correct.
     * @gir-type Enum
     */
    enum AssistantPageType {
        /**
         * The page has regular contents.
         */
        CONTENT,
        /**
         * The page contains an introduction to the
         *  assistant task.
         */
        INTRO,
        /**
         * The page lets the user confirm or deny the
         *  changes.
         */
        CONFIRM,
        /**
         * The page informs the user of the changes
         *  done.
         */
        SUMMARY,
        /**
         * Used for tasks that take a long time to
         *  complete, blocks the assistant until the page is marked as complete.
         */
        PROGRESS,
    }


