        /**
         * @param event 
         * @virtual
         */
        vfunc_scroll_event(event: Gdk.EventScroll): boolean;

        /**
         * @param event 
         * @virtual
         */
        vfunc_selection_clear_event(event: Gdk.EventSelection): boolean;

